import numpy as np

def linear_schedule(T: int, beta_start: float = 1e-4, beta_end: float = 0.02) -> np.ndarray:
    return np.linspace(beta_start, beta_end, T)

def cosine_schedule(T: int, s: float = 0.008) -> np.ndarray:
    steps = T + 1  # need T+1 values for f(0)...f(T)
    t = np.arange(steps)
    f = np.cos(((t / T) + s) / (1 + s) * np.pi / 2) ** 2
    alpha_bars = f / f[0]  # normalize so alpha_bar_0 = 1
    # beta_t = 1 - alpha_bar_t / alpha_bar_{t-1} for t = 1..T
    betas = 1 - alpha_bars[1:] / alpha_bars[:-1]
    return np.clip(betas, 0, 0.999)
